use html_to_markdown_rs::{conversion_options_from_json, convert};

#[test]
fn test_options_code_block_backticks() {
    // Backticks code block style uses triple backtick fences
    let html = r#"<pre><code class="language-js">console.log('hi');</code></pre>"#;
    let options_json = r#"{"codeBlockStyle":"backticks"}"#;
    let options = conversion_options_from_json(options_json).expect("valid options");
    let result = convert(html, Some(options)).expect("conversion should succeed");
    let content = result.content.unwrap_or_default();

    assert!(content.contains("```"), "expected content to contain: ```");
    assert!(
        content.contains("console.log('hi');"),
        "expected content to contain: console.log('hi');"
    );
}

