#[test]
fn test_options_escape_asterisks() {
    // escape_asterisks option escapes asterisks in plain text
    let html = r#"<p>Use 2*3 = 6 in math.</p>"#;
    let options_json = r#"{"escapeAsterisks":true}"#;
    let options = conversion_options_from_json(options_json).expect("valid options");
    let result = convert(html, Some(options)).expect("conversion should succeed");
    let content = result.content.unwrap_or_default();

    assert!(!content.trim().is_empty(), "expected non-empty content");
    assert!(content.contains("2"), "expected content to contain: 2");
    assert!(content.contains("3"), "expected content to contain: 3");
    assert!(content.contains("6"), "expected content to contain: 6");
}

