#[test]
fn test_options_output_format_plain() {
    // Plain text output format strips markdown syntax
    let html = r#"<h1>Title</h1><p>Some <strong>bold</strong> text.</p>"#;
    let options_json = r#"{"outputFormat":"plain"}"#;
    let options = conversion_options_from_json(options_json).expect("valid options");
    let result = convert(html, Some(options)).expect("conversion should succeed");
    let content = result.content.unwrap_or_default();

    assert!(content.contains("Title"), "expected content to contain: Title");
    assert!(content.contains("bold"), "expected content to contain: bold");
    assert!(content.contains("text."), "expected content to contain: text.");
    assert!(
        !content.contains("**bold**"),
        "expected content NOT to contain: **bold**"
    );
    assert!(!content.contains("# Title"), "expected content NOT to contain: # Title");
}

